"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[880],{57373:e=>{e.exports=JSON.parse('{"functions":[{"name":"Define","desc":"Defines a Schema from the provided datatypes.  \\nThis supports tuples, however due to luau limitations you will need to manually annotate the type.\\n\\n```lua title=\\"tupleExample.luau\\"\\nlocal Pack = require(path.to.pack)\\n\\n-- The type of this schema will implicitly be infered as CFrame\\nlocal exampleSchema = Pack:Define(Pack.CFrame)\\n\\n-- For tuples, you must explicitly annotate the type of the schema using Pack.Schema<...>. \\n-- The luau type solver can only infer the first argument.\\nlocal tupleSchema = Pack:Define(Pack.CFrame, Pack.Vector3) :: Pack.Schema<CFrame, Vector3>\\n```","params":[{"name":"...","desc":"See all datatypes in Docs/Datatypes","lua_type":"Datatype"}],"returns":[{"desc":"","lua_type":"Schema"}],"function_type":"method","source":{"line":110,"path":"src/init.luau"}},{"name":"Reflect","desc":"Navigates through Dictionary and SparseDictionary structures to form a schema from lower in the tree.\\nOnly works for schemas which start as either a Dictionary (aka Struct) or SparseDictionary.\\nDoes not support tuple schemas.","params":[{"name":"schema","desc":"The schema to introspect","lua_type":"Schema"},{"name":"path","desc":"a / separated path to the specific node in the schema to copy","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Schema"}],"function_type":"method","source":{"line":146,"path":"src/init.luau"}},{"name":"GetReader","desc":"Returns the internal buffer reader library. Use this with Pack.Custom","params":[],"returns":[{"desc":"","lua_type":"Reader"}],"function_type":"method","source":{"line":186,"path":"src/init.luau"}},{"name":"GetWriter","desc":"Returns the internal buffer writer library. Use this with Pack.Custom","params":[],"returns":[{"desc":"","lua_type":"Writer"}],"function_type":"method","source":{"line":194,"path":"src/init.luau"}},{"name":"GetBitReader","desc":"Returns the internal bitbuffer reader library. Use this with Pack.Custom","params":[],"returns":[{"desc":"","lua_type":"BitReader"}],"function_type":"method","source":{"line":202,"path":"src/init.luau"}},{"name":"GetBitWriter","desc":"Returns the internal bitbuffer writer library. Use this with Pack.Custom","params":[],"returns":[{"desc":"","lua_type":"BitWriter"}],"function_type":"method","source":{"line":210,"path":"src/init.luau"}},{"name":"GetConfig","desc":"Returns the parsed pack configuration. This will be the same as the pack-config module if it is found, as the parser directly modifies that table.","params":[],"returns":[{"desc":"","lua_type":"{ [any]: any }"}],"function_type":"method","source":{"line":218,"path":"src/init.luau"}},{"name":"GetSchemaRead","desc":"[ADVANCED]: Returns the schema read function so you can skip a namecall operation when reading a packet","params":[],"returns":[{"desc":"","lua_type":"<T, U...>(schema: Schema<T, U...>, T, U...) -> (buffer, refs?)"}],"function_type":"method","source":{"line":226,"path":"src/init.luau"}},{"name":"GetSchemaWrite","desc":"[ADVANCED]: Returns the schema write function so you can skip a namecall operation when writing a packet","params":[],"returns":[{"desc":"","lua_type":"<T, U...>(schema: Schema<T, U...>, buff: buffer, refs: refs?) -> (T, U...)"}],"function_type":"method","source":{"line":234,"path":"src/init.luau"}}],"properties":[],"types":[],"name":"Pack","desc":"The singleton object from where Schemas are created and Datatypes can be accessed.\\n\\nThe constructor for Schemas is accessed with `:` syntax  \\nDatatypes are accessed with `.` syntax  \\nAll default datatypes can be found in [Docs/Datatypes](../docs/Datatypes/Primitives)","source":{"line":89,"path":"src/init.luau"}}')}}]);